import React, { useEffect, useState } from 'react';
import axios from 'axios';

function ListaAgendamentos({ reloadKey, onEditar }) {
  const [agendamentos, setAgendamentos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
    setCarregando(true);
    axios.get('/api/agendamentos')
      .then((res) => {
        setAgendamentos(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error('Erro ao buscar agendamentos:', err);
        setCarregando(false);
      });
  }, [reloadKey]);

  const handleDeletar = (id) => {
    if (window.confirm('Tem certeza que deseja deletar este agendamento?')) {
      axios.delete(`/api/agendamentos/${id}`)
        .then(() => {
          setAgendamentos(agendamentos.filter(a => a.id !== id));
        })
        .catch(() => alert('Erro ao deletar agendamento'));
    }
  };

  if (carregando) return <p>Carregando agendamentos...</p>;
  if (agendamentos.length === 0) return <p>Nenhum agendamento cadastrado.</p>;

  return (
    <div>
      <h2>Lista de Agendamentos</h2>
      <ul>
        {agendamentos.map((a) => (
          <li key={a.id}>
            <b>{a.data}</b> {a.hora} | Aluno: {a.aluno} | Disciplina: {a.disciplina} | Paciente: {a.paciente}
            {' | '}Status: {a.status}
            {' | '}Recepção: {a.solicitado_por_recepcao ? 'Sim' : 'Não'}
            {a.observacoes && ` | Obs: ${a.observacoes}`}
            <button onClick={() => onEditar(a)}>Editar</button>
            <button onClick={() => handleDeletar(a.id)}>Deletar</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default ListaAgendamentos;
